        int* heap = new int[numsSize];
        for (int i = 0; i < numsSize; i++) {
            heap[i] = nums[i];
        }
        removeMax(heap, numsSize);
        return heap;
    }

    void removeMax(int* heap, int heapSize) {
        int maxIndex = 0;
        for (int i = 1; i < heapSize; i++) {
            if (heap[i] > heap[maxIndex]) {
                maxIndex = i;
            }
        }
        heap[0] = heap[maxIndex];
        heap[maxIndex] = 0;
        heapify(heap, heapSize - 1, 0);
    }

    void heapify(int* heap, int heapSize, int i) {
        int largest = i;
        int left = 2 * i + 1;
        int right = 2 * i + 2;
        if (left < heapSize && heap[left] > heap[largest]) {
            largest = left;
        }
        if (right < heapSize && heap[right] > heap[largest]) {
            largest = right;
        }
        if (largest != i) {
            swap(heap, i, largest);
            heapify(heap, heapSize, largest);
        }
    }

    void swap(int* a, int* b) {
        int temp = *a;
        *a = *b;
        *b = temp;
    }
};

