class Solution:
    def recoverMaxHeap(self, nums):
        heap = nums[:]
        self.removeMax(heap)
        return heap

    def removeMax(self, heap):
        maxIndex = 0
        for i in range(1, len(heap)):
            if heap[i] > heap[maxIndex]:
                maxIndex = i
        heap[0] = heap[maxIndex]
        heap[maxIndex] = 0
        self.heapify(heap)

    def heapify(self, heap):
        largest = 0
        left = 2 * largest + 1
        right = 2 * largest + 2
        if left < len(heap) and heap[left] > heap[largest]:
            largest = left
        if right < len(heap) and heap[right] > heap[largest]:
            largest = right
        if largest != 0:
            self.swap(heap, 0, largest)
            self.heapify(heap)

    def swap(self, heap, i, j):
        heap[i], heap[j] = heap[j], heap[i]

